1254: int TLSX_ConnectionID_Parse(WOLFSSL* ssl, const byte* input, word16 length,
1255:     byte isRequest)
1256: {
1257:     CIDInfo* info;
1258:     byte cidSz;
1259:     TLSX* ext;
1260: 
1261:     ext = TLSX_Find(ssl->extensions, TLSX_CONNECTION_ID);
1262:     if (ext == NULL) {
1263:         /* CID not enabled */
1264:         if (isRequest) {
1265:             WOLFSSL_MSG("Received CID ext but it's not enabled, ignoring");
1266:             return 0;
1267:         }
1268:         else {
1269:             WOLFSSL_MSG("CID ext not requested by the Client, aborting");
1270:             return UNSUPPORTED_EXTENSION;
1271:         }
1272:     }
1273: 
1274:     if (length < OPAQUE8_LEN)
1275:         return BUFFER_ERROR;
1276: 
1277:     cidSz = *input;
1278:     if (cidSz + OPAQUE8_LEN > length)
1279:         return BUFFER_ERROR;
1280: 
1281:     info = DtlsCidGetInfo(ssl);
1282:     if (info == NULL)
1283:         return BAD_STATE_E;
1284: 
1285:     /* it may happen if we process two ClientHello because the server sent an
1286:      * HRR/HVR request */
1287:     if (info->tx != NULL || info->negotiated) {
1288:         if (ssl->options.side != WOLFSSL_SERVER_END &&
1289:             ssl->options.serverState != SERVER_HELLO_RETRY_REQUEST_COMPLETE &&
1290:             !IsSCR(ssl))
1291:             return BAD_STATE_E;
1292: 
1293:         /* Should not be null if negotiated */
1294:         if (info->tx == NULL)
1295:             return BAD_STATE_E;
1296: 
1297:         /* For now we don't support changing the CID on a rehandshake */
1298:         if (cidSz != info->tx->length ||
1299:                 XMEMCMP(info->tx->id, input + OPAQUE8_LEN, cidSz) != 0)
1300:             return DTLS_CID_ERROR;
1301:     }
1302:     else if (cidSz > 0) {
1303:         ConnectionID* id = (ConnectionID*)XMALLOC(sizeof(*id) + cidSz,
1304:                 ssl->heap, DYNAMIC_TYPE_TLSX);
1305:         if (id == NULL)
1306:             return MEMORY_ERROR;
1307:         XMEMCPY(id->id, input + OPAQUE8_LEN, cidSz);
1308:         id->length = cidSz;
1309:         info->tx = id;
1310:     }
1311: 
1312:     info->negotiated = 1;
1313:     if (isRequest)
1314:         ext->resp = 1;
1315: 
1316:     return 0;
1317: }
