409:             *tp = WOLFSSL_CERT_TYPE_UNKNOWN;
410:         }
411:     }
412:     /* Check certificate type negotiated. */
413:     else if (ssl->options.rpkState.sending_ServerCertTypeCnt == 1) {
414:         *tp = ssl->options.rpkState.sending_ServerCertTypes[0];
415:     }
416:     else {
417:         *tp = WOLFSSL_CERT_TYPE_UNKNOWN;
418:     }
419:     return ret;
420: }
