423: /* Certificate verification options. */
424: typedef struct {
425:     /* Verify the peer certificate. */
426:     byte verifyPeer:1;
427:     /* No peer certificate verification. */
428:     byte verifyNone:1;
429:     /* Fail when no peer certificate seen. */
430:     byte failNoCert:1;
431:     /* Fail when no peer certificate except when PSK handshake performed. */
432:     byte failNoCertxPSK:1;
433: #if defined(WOLFSSL_TLS13) && defined(WOLFSSL_POST_HANDSHAKE_AUTH)
434:     /* Verify peer certificate post handshake. */
435:     byte verifyPostHandshake:1;
436: #endif
437: } SetVerifyOptions;
438: 
439: /* Convert the mode flags into certificate verification options.
440:  *
441:  * @param [in] mode  Certificate verification mode flags.
442:  * @return  Certificate verification options.
443:  */
444: static SetVerifyOptions ModeToVerifyOptions(int mode)
445: {
446:     SetVerifyOptions opts;
447: 
448:     /* Set the options to the default - none set. */
449:     XMEMSET(&opts, 0, sizeof(SetVerifyOptions));
450: 
451:     /* When the mode is not default - set the options. */
452:     if (mode != WOLFSSL_VERIFY_DEFAULT) {
453:         opts.verifyNone = (mode == WOLFSSL_VERIFY_NONE);
454:         /* When not no verification, set the chosen options. */
455:         if (!opts.verifyNone) {
456:             opts.verifyPeer          =
457:                     (mode & WOLFSSL_VERIFY_PEER) != 0;
458:             opts.failNoCertxPSK      =
459:                     (mode & WOLFSSL_VERIFY_FAIL_EXCEPT_PSK) != 0;
460:             opts.failNoCert          =
461:                     (mode & WOLFSSL_VERIFY_FAIL_IF_NO_PEER_CERT) != 0;
462: #if defined(WOLFSSL_TLS13) && defined(WOLFSSL_POST_HANDSHAKE_AUTH)
463:             opts.verifyPostHandshake =
464:                     (mode & WOLFSSL_VERIFY_POST_HANDSHAKE) != 0;
465: #endif
466:         }
467:     }
468: 
469:     return opts;
470: }
471: 
472: /* Set the verification options against the SSL/TLS context.
473:  *
474:  * @param [in] ctx              SSL/TLS context object.
475:  * @param [in] mode             Verification mode options.
476:  * @param [in] verify_callback  Verification callback.
477:  */
478: WOLFSSL_ABI void wolfSSL_CTX_set_verify(WOLFSSL_CTX* ctx, int mode,
479:     VerifyCallback verify_callback)
480: {
481:     WOLFSSL_ENTER("wolfSSL_CTX_set_verify");
482: 
483:     /* Ensure we have an SSL/TLS context to work with. */
484:     if (ctx != NULL) {
485:         SetVerifyOptions opts = ModeToVerifyOptions(mode);
486: 
487:         /* Set the bitfield options. */
488:         ctx->verifyNone     = opts.verifyNone;
489:         ctx->verifyPeer     = opts.verifyPeer;
490:         ctx->failNoCert     = opts.failNoCert;
491:         ctx->failNoCertxPSK = opts.failNoCertxPSK;
492:     #if defined(WOLFSSL_TLS13) && defined(WOLFSSL_POST_HANDSHAKE_AUTH)
493:         ctx->verifyPostHandshake = opts.verifyPostHandshake;
494:     #endif
495: 
496:         /* Store the user verification callback against the context. */
497:         ctx->verifyCallback = verify_callback;
498:     }
499: }
